// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

contract MyNFT is ERC721, Ownable, Pausable, ReentrancyGuard {
    using Strings for uint256;

    string private baseURI;
    uint256 public currentSupply;
    uint256 public maxSupply;
    uint256 public cost;
    bool public mintingOpen;
    bool public revealed;
    address[] public whitelistedAddresses;
    mapping(address => bool) public isWhitelisted;

    event NFTMinted(uint256 tokenId);
    event NFTRevealed();

    constructor(
        string memory _name,
        string memory _symbol,
        string memory _initBaseURI,
        uint256 _maxSupply,
        uint256 _cost
    ) ERC721(_name, _symbol) {
        setBaseURI(_initBaseURI);
        maxSupply = _maxSupply;
        cost = _cost;
        mintingOpen = false;
        revealed = false;
    }

    modifier notPaused() {
        require(!paused(), "Contract is paused");
        _;
    }

    modifier onlyWhenMintingOpen() {
        require(mintingOpen, "Minting is not open");
        _;
    }

    function pause(bool _state) external onlyOwner {
        if (_state) {
            _pause();
        } else {
            _unpause();
        }
    }

    function toggleMintingOpen() external onlyOwner {
        mintingOpen = !mintingOpen;
    }

    function whitelistUser(address user) external onlyOwner {
        require(!isWhitelisted[user], "User already whitelisted");
        whitelistedAddresses.push(user);
        isWhitelisted[user] = true;
    }

    function removeWhitelistUser(address user) external onlyOwner {
        require(isWhitelisted[user], "User not whitelisted");
        delete isWhitelisted[user];
    }

    function whitelistUsers(address[] calldata users) external onlyOwner {
        for (uint256 i = 0; i < users.length; i++) {
            if (!isWhitelisted[users[i]]) {
                whitelistedAddresses.push(users[i]);
                isWhitelisted[users[i]] = true;
            }
        }
    }

    function removeWhitelistUsers(address[] calldata users) external onlyOwner {
        for (uint256 i = 0; i < users.length; i++) {
            if (isWhitelisted[users[i]]) {
                delete isWhitelisted[users[i]];
            }
        }
    }

    function mint() external payable notPaused onlyWhenMintingOpen {
        require(currentSupply < maxSupply, "Max supply reached");
        require(isWhitelisted[msg.sender], "Not whitelisted");
        require(msg.value >= cost, "Insufficient funds");

        uint256 tokenId = currentSupply + 1;
        _safeMint(msg.sender, tokenId);
        currentSupply++;

        emit NFTMinted(tokenId);
    }

    function reveal(string memory _newBaseURI) external onlyOwner {
        require(!revealed, "Already revealed");
        baseURI = _newBaseURI;
        revealed = true;

        emit NFTRevealed();
    }

    function setBaseURI(string memory _newBaseURI) internal onlyOwner {
        baseURI = _newBaseURI;
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function tokenURI(uint256 tokenId) public view virtual override returns (string memory) {
        require(_exists(tokenId), "Token does not exist");
        string memory base = baseURI;
        return bytes(base).length > 0 ? string(abi.encodePacked(base, tokenId.toString())) : "";
    }
}
